def update_uf(uf: Optional[UnionFind], edge: dict) -> Tuple[UnionFind, dict]:
    if uf is None:
        uf = UnionFind()

    u = edge["u"]
    v = edge["v"]
    merged, size = uf.union(u, v)
    if merged:
        result = {
            "u": u,
            "v": v,
            "status": "merged",
            "new_component_size": size
        }
    else:
        result = {
            "u": u,
            "v": v,
            "status": "already_connected",
            "component_size": size
        }
    return uf, result

